global.set('robot', {
  x:140, y:95, angle:0, speed:100, battery:98,
  payload:false, docked:false, dockedStation:null, state:'running'
});
global.set('sensors', {vib:22, temp:36.2});
global.set('activeTemplates', []);
global.set('speedLimit', 100);
global.set('riskScore', 0);
global.set('predAlert', false);
global.set('vibHistory', []);
global.set('tempHistory', []);
global.set('isPatrolling', false);
global.set('isDocking', false);
global.set('isFollowingPath', false);
global.set('activePath', []);
global.set('activePathIndex', 0);
global.set('patrolIndex', 0);
global.set('currentZone', 'A');
global.set('lastZone', 'A');
global.set('vibTrend', 'stable');
global.set('waypointSet', false);
global.set('waypointX', 0);
global.set('waypointY', 0);
node.status({fill:'green', shape:'dot', text:'Initialized ✓'});
msg.payload = {status:'initialized', timestamp:new Date().toISOString()};
return msg;

// ── Retrieve state ──
let s  = global.get('sensors')  || {vib:22, temp:36.2};
let r  = global.get('robot')    || {x:140,y:95,angle:0,speed:100,battery:98,payload:false,docked:false,state:'running'};
let sl = global.get('speedLimit') || 100;
let vH = global.get('vibHistory')  || [];
let tH = global.get('tempHistory') || [];
let isPat = global.get('isPatrolling')   || false;
let isDk  = global.get('isDocking')      || false;
let isPath= global.get('isFollowingPath')|| false;
let aPath = global.get('activePath')     || [];
let aIdx  = global.get('activePathIndex')|| 0;
let pIdx  = global.get('patrolIndex')    || 0;
const DOCK_X=50, DOCK_Y=150;
const PATROL=[{x:80,y:50},{x:220,y:50},{x:250,y:150},{x:150,y:170},{x:50,y:150},{x:80,y:50}];

const events = [];

// ── Helper: move robot one step toward target ──
function moveTowards(tx, ty, speed) {
  const dx=tx-r.x, dy=ty-r.y;
  const dist=Math.sqrt(dx*dx+dy*dy);
  if (dist < 4) return true;
  r.angle = Math.atan2(dy,dx);
  r.x += dx/dist*Math.min(speed,dist);
  r.y += dy/dist*Math.min(speed,dist);
  return false;
}

// ── Helper: determine zone ──
const ZONES=[{id:'A',x1:0,y1:0,x2:160,y2:100},{id:'B',x1:160,y1:0,x2:300,y2:100},{id:'C',x1:0,y1:100,x2:100,y2:200},{id:'D',x1:100,y1:100,x2:300,y2:200}];
function getZone(x,y){for(const z of ZONES)if(x>=z.x1&&x<z.x2&&y>=z.y1&&y<z.y2)return z.id;return 'A';}

if (!r.docked) {
  // Sensor drift
  s.vib  = Math.min(100, Math.max(0, s.vib  + (Math.random()-0.5)*5));
  s.temp = Math.min(80,  Math.max(20, s.temp + (Math.random()-0.5)*1.2));
  if (r.state==='running') r.battery = Math.max(0, r.battery - Math.random()*0.18);
  if (Math.random()<0.025)  r.payload = !r.payload;

  if (r.state === 'running') {
    if (isPath && aPath.length > 0) {
      if (moveTowards(aPath[aIdx].x, aPath[aIdx].y, (sl/100)*3.5)) {
        aIdx++;
        if (aIdx >= aPath.length) {
          isPath=false; aPath=[]; aIdx=0;
          events.push({event:'path_complete', msg:'All waypoints reached'});
        } else {
          events.push({event:'waypoint_reached', index:aIdx, next:aPath[aIdx]});
        }
        global.set('activePath',aPath); global.set('activePathIndex',aIdx); global.set('isFollowingPath',isPath);
      }
    } else if (isDk) {
      if (moveTowards(DOCK_X, DOCK_Y, (sl/100)*3)) {
        r.docked=true; r.dockedStation='Charging Station'; r.state='idle';
        isDk=false; global.set('isDocking',false);
        events.push({event:'docked', station:'Charging Station'});
      }
    } else if (global.get('waypointSet')) {
      const wx=global.get('waypointX'), wy=global.get('waypointY');
      if (moveTowards(wx, wy, (sl/100)*3.5)) {
        global.set('waypointSet',false);
        events.push({event:'waypoint_arrived', zone:getZone(wx,wy)});
      }
    } else if (isPat) {
      if (moveTowards(PATROL[pIdx%PATROL.length].x, PATROL[pIdx%PATROL.length].y, (sl/100)*3)) {
        pIdx++; global.set('patrolIndex',pIdx);
        events.push({event:'patrol_waypoint', index:pIdx});
      }
    } else {
      // Free drift
      r.x = Math.min(295,Math.max(5, r.x+(Math.random()-0.5)*5*(sl/100)));
      r.y = Math.min(195,Math.max(5, r.y+(Math.random()-0.5)*5*(sl/100)));
    }
    r.speed = Math.min(sl, r.speed+1);
  }
} else {
  // Charging at dock
  r.battery = Math.min(100, r.battery+0.5);
  s.temp    = Math.max(20,  s.temp-0.2);
  s.vib     = Math.max(0,   s.vib-1);
}

// ── Update histories ──
vH.push(s.vib); tH.push(s.temp);
if(vH.length>120) vH.shift(); if(tH.length>120) tH.shift();

// ── Risk score ──
const risk = Math.min(100, s.vib*0.6 + Math.max(0,s.temp-40)*1.5);

// ── Predictive alert ──
let predAlert = global.get('predAlert') || false;
if(s.vib>65 && !predAlert) predAlert=true;
else if(s.vib<48) predAlert=false;

// ── Zone detection ──
const zone    = getZone(r.x, r.y);
const lastZone= global.get('lastZone') || 'A';
if(zone !== lastZone) {
  events.push({event:'zone_change', from:lastZone, to:zone});
  global.set('lastZone', zone);
}

// ── Vibration trend ──
let trend='stable';
if(vH.length>=8){const d=vH[vH.length-1]-vH[vH.length-8];if(d>6)trend='rising sharply';else if(d>2)trend='rising';}

// ── Save global state ──
global.set('sensors',s); global.set('robot',r); global.set('riskScore',risk);
global.set('predAlert',predAlert); global.set('vibHistory',vH); global.set('tempHistory',tH);
global.set('currentZone',zone); global.set('vibTrend',trend);

const sensorMsg = {payload:{sensors:s,robot:r,riskScore:risk,predAlert,currentZone:zone,trend,timestamp:new Date().toISOString()},topic:'sensor_update'};
const eventMsg  = events.length ? {payload:events,topic:'motion_events'} : null;

node.status({fill:risk>70?'red':risk>40?'yellow':'green',shape:'dot',text:`V:${s.vib.toFixed(1)} T:${s.temp.toFixed(1)} R:${risk.toFixed(0)}%`});
return [sensorMsg, eventMsg];

const s  = global.get('sensors')       || {};
let   r  = global.get('robot')          || {};
const tpl= global.get('activeTemplates')|| [];
const sl = global.get('speedLimit')     || 100;
const pred=global.get('predAlert')      || false;
const msgs = [];

// 1. Heat Guard
if(tpl.includes('heat') && s.temp>55 && r.speed>60){
  r.speed=60;
  msgs.push({payload:{template:'heat',action:'speed_capped',value:60,reason:`Temp ${s.temp.toFixed(1)}°C > 55°C`},topic:'template_action'});
}
// 2. Low Battery Return
if(tpl.includes('batt') && r.battery<20 && r.state==='running' && !r.docked && !global.get('isDocking')){
  global.set('isDocking',true);
  msgs.push({payload:{template:'batt',action:'auto_docking',reason:`Battery ${r.battery.toFixed(0)}% < 20%`},topic:'template_action'});
}
// 3. Vibration Shield
if(tpl.includes('vib') && s.vib>70 && r.speed>50){
  r.speed=50;
  msgs.push({payload:{template:'vib',action:'speed_capped',value:50,reason:`Vib ${s.vib.toFixed(1)}% > 70%`},topic:'template_action'});
}
// 4. Smart Navigation (stochastic obstacle avoidance)
if(tpl.includes('nav') && Math.random()<0.05){
  r.angle=(r.angle||0)+(Math.random()-0.5)*0.3;
  msgs.push({payload:{template:'nav',action:'rerouting',reason:'Obstacle detected within 1.5 m'},topic:'template_action'});
}
// 5. Predictive Maintenance
if(tpl.includes('maint') && pred && Math.random()<0.1){
  msgs.push({payload:{template:'maint',action:'maintenance_advisory',reason:'Vibration trend indicates bearing failure risk'},topic:'template_action'});
}

global.set('robot',r);
if(!msgs.length) return null;
return msgs;

const s    = global.get('sensors')  || {};
const r    = global.get('robot')    || {};
const risk = global.get('riskScore')|| 0;
const pred = global.get('predAlert')|| false;
const isDk = global.get('isDocking')|| false;
const isPat= global.get('isPatrolling')||false;
const isPath=global.get('isFollowingPath')||false;
const aPath=global.get('activePath')||[];
const aIdx=global.get('activePathIndex')||0;
const alerts=[];

if(s.temp>58) alerts.push({level:'danger',type:'temp',   message:`🔥 Critical temp: ${s.temp.toFixed(1)}°C — shutdown risk`});
else if(s.temp>45) alerts.push({level:'warn',type:'temp',message:`🌡️ High temp: ${s.temp.toFixed(1)}°C — monitor closely`});

if(s.vib>70) alerts.push({level:'danger',type:'vib',    message:`📳 Critical vibration: ${s.vib.toFixed(1)}% — reduce speed`});
else if(s.vib>40) alerts.push({level:'warn',type:'vib', message:`⚡ Elevated vibration: ${s.vib.toFixed(1)}%`});

if(r.battery<20) alerts.push({level:'danger',type:'batt',message:`🔋 Critical battery: ${r.battery.toFixed(0)}% — return to charger`});
else if(r.battery<35) alerts.push({level:'warn',type:'batt',message:`🔋 Low battery: ${r.battery.toFixed(0)}%`});

if(pred) alerts.push({level:'warn',type:'predictive',   message:'🔮 Predictive: motor failure risk rising'});
if(r.state==='error') alerts.push({level:'danger',type:'system',message:'🚨 Robot in error state — manual intervention required'});
if(r.docked) alerts.push({level:'ok',type:'dock',        message:`⚡ Docked at ${r.dockedStation||'station'} — charging`});
if(isDk) alerts.push({level:'info',type:'dock',           message:'🔌 Docking — navigating to charging station'});
if(isPat) alerts.push({level:'info',type:'patrol',        message:'🔁 Patrol route active'});
if(isPath) alerts.push({level:'info',type:'path',         message:`🗺️ Path following — WP ${aIdx+1}/${aPath.length}`});

node.status({fill:alerts.some(a=>a.level==='danger')?'red':alerts.length>0?'yellow':'green',shape:'dot',text:`${alerts.length} alerts`});
msg.payload=alerts; msg.topic='alerts';
return msg;

let s = global.get('sensors') || {};
if(msg.payload.vib !== undefined) s.vib = msg.payload.vib;
if(msg.payload.temp !== undefined) s.temp = msg.payload.temp;
global.set('sensors',s);
msg.payload={status:'fault_injected',sensors:s};
node.status({fill:'red',shape:'ring',text:`Fault: vib=${s.vib}%`});
return msg;

const id  = msg.payload;
const act = msg.topic === 'activate';
let tpl   = global.get('activeTemplates') || [];
const nameMap = {heat:'Prevent Overheating',batt:'Low Battery Return',vib:'Avoid High Vibration',maint:'Predictive Maintenance',nav:'Smart Navigation'};

if(act && !tpl.includes(id)) tpl.push(id);
if(!act) tpl = tpl.filter(t => t !== id);
global.set('activeTemplates', tpl);

msg.payload = {template:id, name:nameMap[id]||id, active:act, activeTemplates:tpl};
msg.topic   = 'template_toggle';
node.status({fill:act?'green':'grey', shape:'dot', text:`${id}: ${act?'ON':'OFF'} | Active: [${tpl.join(',')}]`});
return msg;

const d   = msg.payload;
const tpl = global.get('activeTemplates') || [];
if(!tpl.length) return null;

const results = [];

// Heat Guard
if(tpl.includes('heat')){
  const firing = d.sensors.temp > 55;
  results.push({template:'heat',label:'🌡️ Heat Guard',firing,detail:`Temp ${d.sensors.temp.toFixed(1)}°C ${firing?'> 55°C ⚡ TRIGGERED':'≤ 55°C OK'}`});
}
// Low Battery Return
if(tpl.includes('batt')){
  const firing = d.robot.battery < 20;
  results.push({template:'batt',label:'🔋 Low Battery Return',firing,detail:`Battery ${d.robot.battery.toFixed(0)}% ${firing?'< 20% ⚡ DOCKING':'≥ 20% OK'}`});
}
// Vib Shield
if(tpl.includes('vib')){
  const firing = d.sensors.vib > 70;
  results.push({template:'vib',label:'📳 Vib Shield',firing,detail:`Vib ${d.sensors.vib.toFixed(1)}% ${firing?'> 70% ⚡ SPEED CAP':'≤ 70% OK'}`});
}
// Predictive Maintenance
if(tpl.includes('maint')){
  const firing = d.predAlert;
  results.push({template:'maint',label:'🔧 Predictive Maint',firing,detail:`Trend: ${d.trend} ${firing?'⚡ ADVISORY':'– OK'}`});
}
// Smart Navigation
if(tpl.includes('nav')){
  const firing = Math.random()<0.05; // simulated obstacle detection
  results.push({template:'nav',label:'🧠 Smart Nav',firing,detail:`Obstacle scan ${firing?'⚡ REROUTING':'– clear'}`});
}

const firing = results.filter(r=>r.firing);
node.status({fill:firing.length?'red':'green',shape:'dot',text:`${firing.length}/${results.length} templates firing`});
msg.payload = {results, firing, timestamp:d.timestamp};
return msg;

let r  = global.get('robot')    || {};
let sl = global.get('speedLimit') || 100;
const cmd = msg.payload;
switch(cmd){
  case 'start':
    r.state='running'; r.speed=Math.min(sl,100); r.docked=false;
    global.set('isDocking',false); global.set('isPatrolling',false);
    node.status({fill:'green',shape:'dot',text:'Running'});
    break;
  case 'stop':
    r.state='idle'; r.speed=0;
    global.set('isPatrolling',false); global.set('isDocking',false); global.set('isFollowingPath',false);
    node.status({fill:'grey',shape:'dot',text:'Stopped'});
    break;
  case 'estop':
    r.state='error'; r.speed=0;
    global.set('isPatrolling',false); global.set('isDocking',false); global.set('isFollowingPath',false);
    node.status({fill:'red',shape:'ring',text:'EMERGENCY STOP'});
    break;
  case 'manual':
    r.state='running'; r.docked=false;
    node.status({fill:'blue',shape:'dot',text:'Manual'});
    break;
  case 'reset':
    r.state='running'; r.speed=100; r.x=140; r.y=95; r.angle=0;
    r.docked=false; r.dockedStation=null; r.payload=false;
    global.set('speedLimit',100); global.set('isPatrolling',false);
    global.set('isDocking',false); global.set('isFollowingPath',false);
    global.set('activePath',[]); global.set('activePathIndex',0);
    global.set('waypointSet',false);
    let s=global.get('sensors')||{}; s.vib=22; s.temp=36.2; global.set('sensors',s);
    node.status({fill:'green',shape:'dot',text:'Reset to defaults'});
    break;
}
global.set('robot',r);
msg.payload={cmd,robot:r,timestamp:new Date().toISOString()};
return msg;

const v = parseInt(msg.payload);
global.set('speedLimit', v);
let r = global.get('robot') || {};
r.speed = Math.min(r.speed, v);
global.set('robot',r);
node.status({fill:'blue',shape:'dot',text:`Limit: ${v}%`});
msg.payload={speedLimit:v,robotSpeed:r.speed};
return msg;

const cmd = msg.payload;
let r = global.get('robot') || {};
if(r.state==='error') { node.warn('Cannot nav — robot in error state'); return null; }
switch(cmd){
  case 'dock':
    r.state='running'; r.docked=false;
    global.set('isDocking',true); global.set('isPatrolling',false); global.set('isFollowingPath',false);
    node.status({fill:'blue',shape:'dot',text:'Docking…'});
    break;
  case 'patrol':
    const was = global.get('isPatrolling') || false;
    global.set('isPatrolling',!was); global.set('isDocking',false); global.set('patrolIndex',0);
    node.status({fill:!was?'green':'grey',shape:'dot',text:!was?'Patrolling':'Patrol OFF'});
    break;
  case 'spin':
    r.angle = (r.angle||0) + Math.PI*2; // will smoothly animate in tick
    node.status({fill:'yellow',shape:'dot',text:'Spinning…'});
    break;
  case 'waypoint':
    const wx=Math.random()*260+20, wy=Math.random()*160+20;
    global.set('waypointSet',true); global.set('waypointX',wx); global.set('waypointY',wy);
    global.set('isPatrolling',false); global.set('isDocking',false); global.set('isFollowingPath',false);
    node.status({fill:'green',shape:'dot',text:`WP→(${wx.toFixed(0)},${wy.toFixed(0)})`});
    msg.waypointCoords = {x:wx, y:wy};
    break;
}
global.set('robot',r);
msg.payload={cmd,robot:r,isPatrolling:global.get('isPatrolling'),isDocking:global.get('isDocking')};
return msg;

let wps = msg.payload;
if(!Array.isArray(wps)||!wps.length){ node.warn('No valid waypoints'); return null; }
const ZONES=[{id:'A',x1:0,y1:0,x2:160,y2:100},{id:'B',x1:160,y1:0,x2:300,y2:100},{id:'C',x1:0,y1:100,x2:100,y2:200},{id:'D',x1:100,y1:100,x2:300,y2:200}];
function gz(x,y){for(const z of ZONES)if(x>=z.x1&&x<z.x2&&y>=z.y1&&y<z.y2)return z.id;return'A';}

global.set('activePath',wps); global.set('activePathIndex',0); global.set('isFollowingPath',true);
global.set('isDocking',false); global.set('isPatrolling',false);
let r=global.get('robot')||{}; r.docked=false; r.state='running'; global.set('robot',r);

const route=wps.map((w,i)=>`WP${i+1}:(${w.x},${w.y}) Zone ${gz(w.x,w.y)}`).join(' → ');
node.status({fill:'blue',shape:'dot',text:`Path: ${wps.length} WPs`});
msg.payload={status:'path_started',waypoints:wps,route,count:wps.length};
return msg;

const s = global.get('sensors') || {vib:22};
msg.payload = {sensorType:'vibration', value:s.vib, threshold:40};
msg.topic = 'sensor_read';
node.status({fill:'green',shape:'dot',text:`vib=${s.vib.toFixed(1)}%`});
return msg;

let r=global.get('robot')||{};
const was=r.speed;
r.speed=Math.max(20,r.speed-30);
global.set('robot',r);
msg.payload={action:'reduce_speed',from:was,to:r.speed,reason:`vib ${msg.payload.value.toFixed(1)}% > ${msg.payload.threshold}%`};
node.status({fill:'yellow',shape:'dot',text:`Speed: ${was}% → ${r.speed}%`});
return msg;

msg.payload={action:'send_alert',severity:'warning',message:`High vibration: ${msg.payload.value.toFixed(1)}% exceeds threshold ${msg.payload.threshold}%`,timestamp:new Date().toISOString()};
node.status({fill:'red',shape:'ring',text:'Alert sent'});
return msg;

msg.payload={action:'no_action',status:'nominal',value:msg.payload.value};
node.status({fill:'green',shape:'dot',text:'All clear'});
return msg;

let r=global.get('robot')||{};
const target={x:220,y:50,speed:80};
global.set('isDocking',false); global.set('isPatrolling',false); global.set('isFollowingPath',false);
global.set('waypointSet',true); global.set('waypointX',target.x); global.set('waypointY',target.y);
r.state='running'; r.docked=false; global.set('robot',r);
msg.payload={action:'move_to',target,status:'navigating'};
node.status({fill:'blue',shape:'dot',text:`→ (${target.x},${target.y})`});
return msg;

let r=global.get('robot')||{};
r.payload=true; global.set('robot',r);
global.set('waypointSet',false);
msg.payload={action:'pick_payload',type:'Pallet',status:'picked',carrying:true};
node.status({fill:'green',shape:'dot',text:'Payload picked ✓'});
return msg;

const wps=[{x:220,y:50},{x:250,y:150},{x:150,y:170}];
const ZONES=[{id:'A',x1:0,y1:0,x2:160,y2:100},{id:'B',x1:160,y1:0,x2:300,y2:100},{id:'C',x1:0,y1:100,x2:100,y2:200},{id:'D',x1:100,y1:100,x2:300,y2:200}];
function gz(x,y){for(const z of ZONES)if(x>=z.x1&&x<z.x2&&y>=z.y1&&y<z.y2)return z.id;return'A';}
global.set('activePath',wps); global.set('activePathIndex',0); global.set('isFollowingPath',true);
const route=wps.map((w,i)=>`WP${i+1}:Zone ${gz(w.x,w.y)}`).join('→');
msg.payload={action:'path_planning',waypoints:wps,route,status:'following'};
node.status({fill:'blue',shape:'dot',text:`Path: ${wps.length} WPs`});
return msg;

let r=global.get('robot')||{};
const zone=global.get('currentZone')||'D';
r.payload=false; global.set('robot',r);
global.set('isFollowingPath',false); global.set('activePath',[]); global.set('activePathIndex',0);
msg.payload={action:'drop_payload',dropZone:zone,status:'dropped',carrying:false};
node.status({fill:'green',shape:'dot',text:`Dropped at Zone ${zone}`});
return msg;

let r=global.get('robot')||{};
if(r.docked){msg.payload={action:'dock',status:'already_docked'}; return msg;}
global.set('isDocking',true); global.set('isPatrolling',false);
r.state='running'; global.set('robot',r);
msg.payload={action:'dock',status:'docking',loopTarget:msg.payload.loopTarget||2,loopCount:0};
node.status({fill:'blue',shape:'dot',text:'Docking…'});
return msg;

let lc = (msg.payload.loopCount||0)+1;
const lt = msg.payload.loopTarget||2;
msg.payload.loopCount = lc;
node.status({fill:'yellow',shape:'dot',text:`Iter ${lc}/${lt}`});
if(lc <= lt){
  msg.topic = 'loop_iteration';
  return [msg, null];
} else {
  msg.topic = 'loop_done';
  return [null, msg];
}

const zone=global.get('currentZone')||'A';
const watchZone='D';
msg.payload={action:'zone_check',currentZone:zone,watchZone,matched:zone===watchZone};
node.status({fill:'blue',shape:'dot',text:`Zone: ${zone} | Watching: ${watchZone}`});
return msg;

let r=global.get('robot')||{};
r.speed=0; r.state='error';
global.set('robot',r); global.set('isPatrolling',false); global.set('isDocking',false); global.set('isFollowingPath',false);
msg.payload={action:'emergency_stop',reason:`Entered danger Zone ${msg.payload.currentZone}`,resetAfter:5,timestamp:new Date().toISOString()};
node.status({fill:'red',shape:'ring',text:'EMERGENCY STOP ⚡'});
return msg;

msg.payload={action:'zone_safe',zone:msg.payload.currentZone,status:'ok'};
node.status({fill:'green',shape:'dot',text:'Safe zone'});
return msg;

let r=global.get('robot')||{};
r.state='running'; r.speed=60; global.set('robot',r);
msg.payload={action:'auto_resume',speed:60,status:'resumed',timestamp:new Date().toISOString()};
node.status({fill:'green',shape:'dot',text:'Resumed at 60%'});
return msg;

const d=msg.payload;
if(!d||!d.sensors) return null;
const risk=d.riskScore||0;
const status = risk>70?'🔴 CRITICAL':risk>40?'🟡 ELEVATED':'🟢 NOMINAL';
const line=`[${new Date().toLocaleTimeString()}] ${status} | Zone:${d.currentZone} | Vib:${d.sensors.vib.toFixed(1)}% | Temp:${d.sensors.temp.toFixed(1)}°C | Batt:${d.robot.battery.toFixed(0)}% | Spd:${d.robot.speed}% | Risk:${risk.toFixed(0)}%`;
msg.payload=line; msg.topic='status_line';
node.status({fill:risk>70?'red':risk>40?'yellow':'green',shape:'dot',text:status});
return msg;

const alerts=msg.payload||[];
if(!alerts.length){
  msg.payload={level:'ok',message:'✅ All systems normal',timestamp:new Date().toISOString()};
  return [null,null,null,msg];
}
const danger=alerts.filter(a=>a.level==='danger');
const warns =alerts.filter(a=>a.level==='warn');
const infos =alerts.filter(a=>a.level==='info');
const oks   =alerts.filter(a=>a.level==='ok');
const ts=new Date().toISOString();
const mk=(arr,label)=>arr.length?{payload:{alerts:arr,count:arr.length,label,timestamp:ts},topic:'alert'}:null;
return [mk(danger,'DANGER'),mk(warns,'WARNING'),mk([...infos,...oks],'INFO/OK'),null];

const ts=new Date().toLocaleTimeString();
let entry;
if(Array.isArray(msg.payload)){
  entry=msg.payload.map(a=>`[${ts}] [${a.level?.toUpperCase()||'INFO'}] ${a.message||a.detail||JSON.stringify(a)}`).join('\n');
} else if(typeof msg.payload==='object'){
  const p=msg.payload;
  const lvl=(p.level||p.severity||'INFO').toUpperCase();
  entry=`[${ts}] [${lvl}] ${p.message||p.action||p.event||JSON.stringify(p)}`;
} else {
  entry=`[${ts}] [INFO] ${msg.payload}`;
}
msg.payload=entry; msg.topic='event_log';
return msg;
